const oembed = $input.first().json;
const source = $('Fetch curated TikTok URLs').item.json;

// Extract video ID from the TikTok URL stored in channel_id
const url = source.channel_id ?? '';
const videoIdMatch = url.match(/video\/(\d+)/);
const videoId = videoIdMatch ? videoIdMatch[1] : url;

// Skip if oEmbed returned an error
if (!oembed.title && !oembed.author_name) {
  return [];
}

return [{
  json: {
    platform: 'tiktok',
    external_id: videoId,
    title: oembed.title ?? null,
    description: null,
    thumbnail_url: oembed.thumbnail_url ?? null,
    embed_url: url,
    author_name: oembed.author_name ?? null,
    author_avatar_url: oembed.author_avatar_url ?? null,
    view_count: 0,
    like_count: 0,
    tags: source.tags ?? [],
    duration_seconds: null,
    published_at: null,
  }
}];
